import React, { useState, useEffect } from "react";
import { initializeApp } from "firebase/app";
import { getAuth, signInWithPopup, GoogleAuthProvider } from "firebase/auth";

const firebaseConfig = {
  apiKey: "AIzaSyD_XPgAScPZZM-9Lq3BsXpkoep0o-kA0KA",
  authDomain: "anhkhoa-375b5.firebaseapp.com", 
  projectId: "anhkhoa-375b5",
  storageBucket: "anhkhoa-375b5.appspot.com",
  messagingSenderId: "871888210644",
  appId: "1:871888210644:web:2cc9a63af5daf6182ea056"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
const auth = getAuth(app);
const provider = new GoogleAuthProvider();

export default function LoginForm(props) {
  const [input1, setInput1] = useState('');
  const [input2, setInput2] = useState('');
  const [user, setUser] = useState(null);

  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged((user) => {
      setUser(user);
    });
    return () => unsubscribe();
  }, []);

  const handleGoogleLogin = async () => {
    try {
      const result = await signInWithPopup(auth, provider);
      const user = result.user;
      
      // Gửi thông tin user lên server để lưu vào database
      const response = await fetch('http://localhost:3000/api/users', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          email: user.email,
          display_name: user.displayName,
          photo_url: user.photoURL,
          provider: 'google'
        })
      });

      if (response.ok) {
        if (props.onLoginSuccess) {
          props.onLoginSuccess();
        }
      } else {
        throw new Error('Failed to save user data');
      }
    } catch (error) {
      console.error("Error during Google login:", error);
      alert("Đăng nhập thất bại. Vui lòng thử lại.");
    }
  };

  const handleLogin = () => {
    // Ở đây bạn có thể thêm kiểm tra MSSV/mật khẩu
    // Hiện tại chỉ demo chuyển sang HomePage
    if (props.onLoginSuccess) {
      props.onLoginSuccess();
    } else {
      alert("Login pressed!");
    }
  };

  return (
    <div className="min-h-screen bg-blue-400 flex justify-center items-start py-20">
      <div className="bg-blue-300 rounded-xl shadow-lg w-full max-w-[800px] p-16 flex flex-col items-center">
        
        <span className="text-black text-3xl font-semibold mb-12">
          ĐĂNG NHẬP NHÉ
        </span>

        <input
          placeholder="MSSV"
          value={input1}
          onChange={(e) => setInput1(e.target.value)}
          className="w-full max-w-[600px] text-black text-2xl py-4 px-6 mb-6 rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-blue-300"
        />

        <input
          placeholder="Mật khẩu"
          value={input2}
          onChange={(e) => setInput2(e.target.value)}
          type="password"
          className="w-full max-w-[600px] text-black text-2xl py-4 px-6 mb-6 rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-blue-300"
        />

        <button
          onClick={() => alert("Quên mật khẩu")}
          className="self-start mb-4 text-blue-400 font-medium underline"
        >
          Quên mật khẩu
        </button>

        <button
          onClick={handleLogin}
          className="w-full max-w-[300px] bg-blue-300 hover:bg-blue-400 text-black text-2xl py-3 mb-4 rounded-lg border border-black transition"
        >
          Let’s go
        </button>

        {/* Nút chuyển sang Register */}
        <button
          onClick={props.goToRegister}
          className="w-full max-w-[300px] bg-blue-300 hover:bg-blue-400 text-black text-2xl py-3 mb-4 rounded-lg border border-black transition"
        >
          Đăng ký
        </button>

        <button
          onClick={handleGoogleLogin}
          className="w-full max-w-[300px] bg-white hover:bg-gray-100 text-black text-xl py-3 mb-6 rounded-lg border border-gray-300 flex items-center justify-center gap-2 transition"
        >
          <img 
            src="https://www.google.com/favicon.ico" 
            alt="Google icon" 
            className="w-6 h-6"
          />
          Đăng nhập với Google
        </button>

        <span className="text-black text-lg text-center">
          Nhập để được tham gia với chúng tớ nào!!!
        </span>

      </div>
    </div>
  );
}
